import { useState } from "react";

function App() {
  const [userId, setUserId] = useState("");
  const [score, setScore] = useState("");
  const [message, setMessage] = useState("");

  const signup = async () => {
    const res = await fetch("http://localhost:5000/signup", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        email: "test" + Math.random() + "@gmail.com",
        password: "123456",
      }),
    });

    const data = await res.json();
    setUserId(data.data[0].id);
    setMessage("User created!");
  };

  const addScore = async () => {
    await fetch("http://localhost:5000/add-score", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        userId,
        score: Number(score),
      }),
    });

    setMessage("Score added!");
  };

  const subscribe = async () => {
    await fetch("http://localhost:5000/subscribe", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        userId,
      }),
    });

    setMessage("Subscribed!");
  };

  const runDraw = async () => {
    const res = await fetch("http://localhost:5000/run-draw", {
      method: "POST",
    });

    const data = await res.json();
    setMessage("Draw: " + data.numbers.join(", "));
  };

  return (
    <div style={{ padding: 20 }}>
      <h1>Golf App MVP</h1>

      <button onClick={signup}>Signup</button>

      <br /><br />

      <input
        placeholder="User ID"
        value={userId}
        onChange={(e) => setUserId(e.target.value)}
      />

      <br /><br />

      <input
        placeholder="Score"
        value={score}
        onChange={(e) => setScore(e.target.value)}
      />

      <br /><br />

      <button onClick={addScore}>Add Score</button>
      <button onClick={subscribe}>Subscribe</button>
      <button onClick={runDraw}>Run Draw</button>

      <h3>{message}</h3>
    </div>
  );
}

export default App;
